#nullable enable // autogenerated

using MukioI18n;
using MVZ2.GameContent.Effects;
using MVZ2.Vanilla.Audios;
using MVZ2.Vanilla.Definitions;
using MVZ2.Vanilla.Entities;
using MVZ2.Vanilla.Localization;
using MVZ2.Vanilla.RandomChina;
using MVZ2Logic.Entities;
using MVZ2Logic.Level;
using PVZEngine.Entities;
using Tools;

namespace MVZ2.GameContent.RandomChinaEvents
{
    [RandomChinaEventDefinition(VanillaRandomChinaEventNames.theLovers)]
    public class TheLoversEvent : RandomChinaEventDefinition
    {
        public TheLoversEvent(string nsp, string path) : base(nsp, path, NAME, DESCRIPTION)
        {
        }
        public override void Run(Entity contraption, RandomGenerator rng)
        {
            var level = contraption.Level;
            var enemies = level.FindEntities(e => e.Type == EntityTypes.ENEMY && e.ExistsAndAlive() && !e.IsLoyal() && !e.IsCharmed());
            var contraptions = level.FindEntities(e => e.Type == EntityTypes.PLANT && e.ExistsAndAlive() && !e.IsLoyal() && !e.IsCharmed() && e != contraption);
            if (enemies.Length > 0 && contraptions.Length > 0)
            {
                var enemy = enemies.Random(rng);
                enemy.CharmPermanent(VanillaFactions.THE_LOVERS, new EntitySourceReference(contraption));
                enemy.Spawn(VanillaEffectID.mindControlLines, enemy.GetCenter());

                var target = contraptions.Random(rng);
                target.CharmPermanent(VanillaFactions.THE_LOVERS, new EntitySourceReference(contraption));
                target.Spawn(VanillaEffectID.mindControlLines, target.GetCenter());
                contraption.PlaySound(VanillaSoundID.charmed);
                contraption.PlaySound(VanillaSoundID.floop);
            }
            else
            {
                contraption.PlaySound(VanillaSoundID.buzzer);
            }
        }
        [TranslateMsg("随机瓷器事件名称", VanillaStrings.CONTEXT_RANDOM_CHINA_EVENT_NAME)]
        public const string NAME = "VI-恋人";
        [TranslateMsg("随机瓷器事件描述", VanillaStrings.CONTEXT_RANDOM_CHINA_EVENT_DESCRIPTION)]
        public const string DESCRIPTION = "随机将一对器械和怪物变为中立阵营";
    }
}
